  border-radius: 12px;
  width: 100%;
}

.zodiac-symbol {
  font-size: 3rem;
  margin-bottom: 8px;
}

.zodiac-name {
  font-size: 1.2rem;
  color: var(--accent);
  letter-spacing: 0.2em;
}

footer {
  position: relative;
  z-index: 1;
  text-align: center;
  padding: 40px 20px;
  color: var(--text-dim);
  font-size: 0.8rem;
  letter-spacing: 0.2em;
}

/* 加载动画 */
@keyframes spin {
  to { transform: rotate(360deg); }
}

.loading-spinner {
  display: inline-block;
  width: 16px; height: 16px;
  border: 2px solid rgba(255,255,255,0.3);
  border-top-color: white;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
  margin-right: 8px;
  vertical-align: middle;
}

@media (max-width: 600px) {
  header h1 { font-size: 2rem; }
  .tarot-card { width: 140px; }
  .divine-btn { padding: 14px 40px; }
}

